INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Unified protocol support$q$, $q$JMAP, IMAP4rev2, IMAP4rev1, POP3, and SMTP are all served from a single Rust binary, reducing the number of separate services an administrator has to run.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Built-in message authentication$q$, $q$Native DKIM, DMARC, SPF, and ARC support with automated DKIM key rotation help prevent spoofing and improve deliverability without extra tooling.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Integrated calendar and contacts$q$, $q$CalDAV and CardDAV support let Stalwart double as a calendaring and contacts backend alongside email.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Automated TLS and DNS management$q$, $q$ACME-based certificate renewal and direct integration with DNS providers like Cloudflare and Route 53 simplify ongoing certificate and record maintenance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Multi-tenant architecture$q$, $q$Per-user and per-tenant quotas make Stalwart suitable for hosting providers or organizations running mail for multiple domains and departments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Web-based admin dashboard$q$, $q$A browser-based control panel manages accounts, domains, and configuration, with live tracing and real-time dashboards for operational visibility.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Full Sieve scripting$q$, $q$Support for every IANA-registered Sieve extension gives users granular control over mail filtering rules.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Open-source and self-hosted$q$, $q$The Community edition source code is available on GitHub, giving organizations full transparency and control over their email infrastructure.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Consolidates SMTP, IMAP, POP3, JMAP, CalDAV, CardDAV, and WebDAV into one server instead of many separate tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Free and open source Community edition with an active GitHub project$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Modern Rust codebase built for performance and memory safety$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Strong built-in email authentication (DKIM, DMARC, SPF, ARC) reduces reliance on add-on tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Automated DNS and TLS certificate management reduces manual admin overhead$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Self-hosting email requires ongoing operational responsibility for deliverability, security, and uptime$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Enterprise features and premium support require a paid license$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Newer project (founded 2022) with a smaller long-term track record than legacy mail servers like Postfix or Dovecot$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Migrating from an existing mail stack requires planning around DNS, DKIM keys, and client reconfiguration$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Is Stalwart Mail Server free to use$q$, $q$Yes. The Community edition is free and open source. A paid Enterprise edition exists for organizations that want premium support and additional management features, billed per mailbox.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$What protocols does Stalwart support$q$, $q$Stalwart supports JMAP, IMAP4rev2, IMAP4rev1, POP3, SMTP, ManageSieve, CalDAV, CardDAV, and WebDAV in a single server.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Is Stalwart self-hosted or a hosted service$q$, $q$Stalwart is designed to be self-hosted. Organizations run it on their own servers or infrastructure rather than subscribing to a hosted inbox service.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$What programming language is Stalwart written in$q$, $q$Stalwart is written in Rust, which the project cites as contributing to its performance, security, and memory safety.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Who maintains Stalwart Mail Server$q$, $q$Stalwart is developed by Stalwart Labs, a company founded in 2022 and based in London, United Kingdom, with an active open-source community on GitHub, Discord, and Matrix.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Does Stalwart support DKIM and DMARC out of the box$q$, $q$Yes. Stalwart includes built-in support for DKIM, DMARC, SPF, and ARC, including automated DKIM key rotation.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Can Stalwart replace Postfix and Dovecot$q$, $q$Stalwart is designed as an all-in-one replacement for the typical Postfix plus Dovecot combination, handling both SMTP delivery and IMAP or JMAP mailbox access in one server.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Does Stalwart support multiple domains and tenants$q$, $q$Yes. Stalwart has a multi-tenant architecture with per-user and per-tenant quotas, making it suitable for hosting mail for multiple organizations or domains.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Self-hosted email for privacy-focused organizations$q$, $q$Organizations that want full control over their email data and infrastructure can run Stalwart on their own servers instead of using a third-party hosted provider.$q$, $q$System administrators and privacy-conscious teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Consolidating mail, calendar, and contacts infrastructure$q$, $q$Teams that currently run separate SMTP, IMAP, CalDAV, and CardDAV servers can replace them with a single Stalwart deployment.$q$, $q$IT teams and infrastructure engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Mail hosting for multiple domains or clients$q$, $q$Stalwart's multi-tenant architecture and per-mailbox Enterprise pricing suit hosting providers or agencies managing email for multiple client domains.$q$, $q$Managed hosting providers and web agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source core mail server","JMAP, IMAP4, POP3, and SMTP support","CalDAV, CardDAV, and WebDAV support","Built-in DKIM, DMARC, SPF, and ARC","Web-based admin dashboard"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$Enterprise$q$, $q$From about 2 euros per mailbox per year (25 to 499 mailboxes), decreasing at higher volumes$q$, $q$annual or monthly$q$, NULL, $q$["Everything in Community","Premium support (included at 150-plus mailboxes)","Advanced management and monitoring tooling","Priority updates and enterprise licensing"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$overview$q$, $q$What Is Stalwart Mail Server$q$, 2, ARRAY[$q$Stalwart Mail Server is an open-source, self-hosted mail and collaboration platform that consolidates the protocols a modern email deployment needs into a single Rust-based server. Rather than stitching together separate software for SMTP, IMAP, and calendaring, Stalwart bundles JMAP, IMAP4, POP3, SMTP, ManageSieve, CalDAV, CardDAV, and WebDAV support in one codebase.$q$, $q$The project is maintained by Stalwart Labs, a company founded in 2022 and based in London, United Kingdom. It targets administrators and organizations who want full control over their email infrastructure without depending on legacy tools like Postfix and Dovecot, or on third-party hosted inboxes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Stalwart supports modern JMAP clients as well as traditional IMAP and POP3 clients, so it works with both contemporary apps and legacy mail software. Built-in DKIM, DMARC, SPF, and ARC support handle message authentication out of the box, with automated DKIM key rotation on a configurable schedule.$q$, $q$Administration is handled through a web-based dashboard covering account, domain, and configuration management, with real-time monitoring and live tracing for troubleshooting. Multi-tenant architecture allows operators to set per-user and per-tenant storage quotas, and integrated DNS management connects directly to providers such as Cloudflare, Route 53, and Google Cloud DNS for automated record management. ACME-based TLS certificate renewal and full Sieve scripting (including every IANA-registered extension) round out the administrative toolset.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Stalwart is free and open source under its Community edition, which includes the core mail server functionality. An Enterprise edition adds premium features, management tooling, and support, licensed per mailbox at roughly 2 euros per mailbox per year for smaller deployments (25 to 499 mailboxes), with the per-mailbox rate decreasing at higher volumes (down to about 0.89 euros per mailbox at 50,000-plus mailboxes). Sponsors contributing at certain monthly tiers on the project's funding page also receive Enterprise licensing and support access.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db5dc978-1f33-4ece-86f5-07c85e0d3438', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$End-to-end encryption$q$, $q$All notes and files are encrypted on-device with audited encryption before syncing, so Standard Notes itself cannot read user content.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Cross-platform sync$q$, $q$Notes stay in sync across web, Windows, macOS, Linux, iOS, and Android apps.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Markdown and rich editors$q$, $q$Supports plain markdown as well as optional rich text, code, and task-list editors on paid tiers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Nested folders and tags$q$, $q$Notes can be organized with nested folders, tags, and smart filters for quick retrieval.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Note version history$q$, $q$Paid plans retain historical versions of notes so earlier edits can be recovered.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Encrypted file storage$q$, $q$Higher tiers include encrypted file attachments with storage allowances up to 100GB.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Offline access$q$, $q$Notes remain accessible and editable offline, syncing again once a connection is restored.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Subscription sharing$q$, $q$The Professional plan allows a subscription to be shared across multiple people.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Strong, audited end-to-end encryption with a zero-knowledge architecture$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Generous free tier covering core note-taking needs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Cross-platform apps for web, desktop, and mobile$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Open-source clients allow independent security review$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Now backed by Proton's broader privacy infrastructure after the 2024 acquisition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Advanced features like extended history and large file storage require a paid plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Editor and organization features are more minimal than some mainstream note apps$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$No built-in real-time collaborative editing comparable to Notion or Google Docs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Pricing and product direction may shift as integration with Proton continues$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Is Standard Notes really end-to-end encrypted$q$, $q$Yes. Standard Notes encrypts notes and files on-device before syncing, using audited end-to-end encryption, so only the account holder can decrypt their data.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Is Standard Notes free$q$, $q$Yes, Standard Notes has a free tier with core note-taking, markdown, and encryption. Paid Productivity and Professional plans add extended history, more storage, and additional editors.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Who owns Standard Notes now$q$, $q$Standard Notes was acquired by Proton AG in April 2024 and is now part of Proton's suite of privacy products alongside Proton Mail and Proton VPN.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$What platforms does Standard Notes support$q$, $q$Standard Notes has apps for web, Windows, macOS, Linux, iOS, and Android, all syncing the same encrypted note library.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Can I use Standard Notes offline$q$, $q$Yes, notes are accessible and editable offline and sync automatically once the device reconnects.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Does Standard Notes support markdown$q$, $q$Yes, markdown is supported natively, and paid plans add additional editor types such as rich text and code editors.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$How much does Standard Notes cost$q$, $q$Standard Notes offers a free plan, a Productivity plan at roughly 90 dollars per year, and a Professional plan at roughly 120 dollars per year.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Who founded Standard Notes$q$, $q$Standard Notes was founded by Mo Bitar in 2016 in Chicago, Illinois.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Private personal journaling and notes$q$, $q$Individuals who want a private place to keep journals, ideas, and sensitive information use Standard Notes' encrypted storage to keep content away from third-party access.$q$, $q$Privacy-conscious individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Secure notes for journalists and researchers$q$, $q$Professionals handling sensitive sources or research material rely on Standard Notes' zero-knowledge encryption to protect their notes.$q$, $q$Journalists and researchers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Shared encrypted notes for small teams or families$q$, $q$The Professional plan's subscription sharing lets small teams or families maintain their own encrypted note libraries under one subscription.$q$, $q$Small teams and families$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Markdown notes","Nested folders and tags","Cross-platform sync","End-to-end encryption"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Productivity$q$, $q$About $90/year$q$, $q$annual$q$, NULL, $q$["Everything in Free","Extended note version history","Additional editors","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$Professional$q$, $q$About $120/year$q$, $q$annual$q$, NULL, $q$["Everything in Productivity","Up to 100GB encrypted file storage","Subscription sharing"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$overview$q$, $q$What Is Standard Notes$q$, 2, ARRAY[$q$Standard Notes is an end-to-end encrypted note-taking app designed around a simple premise: notes should be private by default. Every note is encrypted on-device before it ever reaches Standard Notes' servers, so only the account holder holds the keys required to decrypt their data.$q$, $q$The app was founded by Mo Bitar in 2016 in Chicago, Illinois, in direct response to privacy policy changes at mainstream note-taking competitors. In April 2024, Standard Notes was acquired by Proton AG, the company behind Proton Mail and Proton VPN, and now sits alongside those products in Proton's privacy-focused suite.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Standard Notes offers markdown editing, nested folders and tags for organization, and smart search, all wrapped in audited end-to-end encryption. Notes sync across web, desktop, and mobile apps so the same encrypted library is accessible everywhere.$q$, $q$Paid tiers extend the free experience with longer note version history, larger encrypted file storage allowances, additional themes and specialized editors (such as rich text, code, and task list editors), and the ability to share a subscription with family members or a small team.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Standard Notes uses a freemium model. The free plan covers core note-taking, markdown, folders, and encryption for individuals who do not need extended history or extra storage. The Productivity plan, priced at roughly 90 dollars per year, adds extended note history and more editors. The Professional plan, at roughly 120 dollars per year, adds larger encrypted file storage (up to 100GB) and subscription sharing for multiple users.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('19834a87-bdcd-4d0a-b9a5-f013e990b7b2', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Automatic navigation$q$, $q$Sidebar navigation is generated automatically from a project's folders and files, reducing manual configuration.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Built-in search$q$, $q$Full-text search powered by Pagefind is included out of the box with no external search service required.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Internationalization$q$, $q$Built-in i18n support makes it straightforward to build and maintain multilingual documentation sites.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Multiple content formats$q$, $q$Supports Markdown, MDX, and Markdoc, giving authors flexibility in how they write content.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Accessible by default$q$, $q$Ships with accessible typography, semantic navigation, and keyboard-friendly components.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Dark and light themes$q$, $q$Includes built-in theme switching between dark and light modes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Minimal JavaScript footprint$q$, $q$Built on Astro's islands architecture, so pages load fast by shipping little client-side JavaScript.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Framework-agnostic components$q$, $q$Supports embedding React, Vue, Svelte, Solid, and other framework components inside documentation pages.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Completely free and open source with no paid tier$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Fast page loads thanks to Astro's minimal-JavaScript approach$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Built-in search, navigation, and i18n reduce setup time$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Actively maintained by the Astro core team with frequent releases$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Flexible content authoring across Markdown, MDX, and Markdoc$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Requires familiarity with Astro and its build tooling$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$No hosted or managed offering; teams must deploy and host it themselves$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Customization beyond the built-in theme requires editing Astro components$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Smaller plugin ecosystem than long-established docs tools like Docusaurus or GitBook$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Is Starlight free to use$q$, $q$Yes, Starlight is completely free and open source with no paid tiers or licensing fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$What is Starlight built on$q$, $q$Starlight is built on Astro, a web framework focused on shipping minimal JavaScript for fast page loads.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Does Starlight include search$q$, $q$Yes, Starlight includes built-in full-text search powered by Pagefind, requiring no external search service.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Can Starlight sites support multiple languages$q$, $q$Yes, Starlight has built-in internationalization support for building multilingual documentation sites.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$What content formats does Starlight support$q$, $q$Starlight supports Markdown, MDX, and Markdoc for writing documentation content.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Who maintains Starlight$q$, $q$Starlight is maintained by the Astro core team as part of the open-source Astro ecosystem, first introduced in 2023.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Can I use React or Vue components in Starlight$q$, $q$Yes, Starlight supports framework-agnostic UI components, so React, Vue, Svelte, and Solid components can be embedded in documentation pages.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Where can I host a Starlight documentation site$q$, $q$Since Starlight generates a static Astro site, it can be hosted anywhere static sites are supported, including Netlify, Vercel, and GitHub Pages.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Open-source project documentation$q$, $q$Open-source maintainers use Starlight to build searchable, well-organized docs for their libraries and tools without building a custom site.$q$, $q$Open-source maintainers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Developer tool and API documentation$q$, $q$Companies building developer tools use Starlight to document APIs and SDKs with fast, accessible, search-enabled sites.$q$, $q$Developer tools and API teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Multilingual product documentation$q$, $q$Teams needing documentation in multiple languages use Starlight's built-in internationalization to manage translated content in one site.$q$, $q$Global product and engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full framework source code","Automatic navigation and search","Internationalization support","Markdown, MDX, and Markdoc support","Community support via GitHub and Discord"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$overview$q$, $q$What Is Starlight$q$, 2, ARRAY[$q$Starlight is a documentation site framework built on Astro, created to give developers a fast path to a polished, accessible documentation website. Rather than building a docs site from scratch, teams configure Starlight and get navigation, search, theming, and internationalization by default.$q$, $q$Starlight is maintained by the Astro core team as an open-source project, first introduced in 2023. It has become a popular choice for open-source project documentation, developer tools, and API references because it emphasizes performance and accessibility without requiring extensive custom development.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Starlight automatically generates site navigation from a project's folder and file structure, and includes built-in full-text search powered by Pagefind so visitors can find content without an external search service.$q$, $q$The framework supports Markdown, MDX, and Markdoc for content authoring, includes built-in internationalization for multilingual documentation sites, and ships dark and light theme support along with accessible typography and code syntax highlighting. Because it is built on Astro, Starlight sends minimal JavaScript to the browser, keeping documentation sites fast, and it supports framework-agnostic components so teams can embed React, Vue, Svelte, or Solid UI where interactivity is needed.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Starlight is completely free and open source. There is no paid tier, subscription, or license fee; teams self-host the generated static site wherever they choose, such as Netlify, Vercel, or GitHub Pages.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ffe3fec8-5847-4750-b01a-593c7901730d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Media tagging and organization$q$, $q$Videos and images can be tagged, categorized, and searched within a personal media library.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Automated metadata scraping$q$, $q$Community-built scrapers pull metadata such as titles, performers, and studios from external sources.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Plugin extensibility$q$, $q$An extensible plugin system lets the community add support for new sources and functionality.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Performer, tag, and studio statistics$q$, $q$Stash tracks and displays statistics across performers, tags, and studios in the library.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$StashDB integration$q$, $q$Connects to StashDB, a crowd-sourced metadata repository, for enriched scene and performer information.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Broad format support$q$, $q$Handles a wide variety of video and image formats, using ffmpeg for transcoding when needed.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Cross-platform self-hosting$q$, $q$Runs via Docker or natively on Windows, macOS, and Linux.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Local web interface$q$, $q$Managed through a browser-based interface hosted locally, by default at localhost:9999.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Completely free and open source under AGPL-3.0$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Full local control over media library and metadata, no cloud dependency$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Active community with extensive plugin and scraper ecosystem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Cross-platform support via Docker, Windows, macOS, and Linux$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Detailed statistics and organization tools for large collections$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Requires self-hosting and basic technical setup (Docker or manual install)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$No official cloud-hosted version from the core project$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Metadata scraping quality depends on community-maintained scrapers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Not related to and easily confused with the Stash personal finance investing app$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Is Stash the same as the Stash investing app$q$, $q$No. Stash (stashapp.cc) is an open-source, self-hosted media organizer written in Go. It is unrelated to the Stash personal finance and investing app.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Is Stash free to use$q$, $q$Yes, Stash is free and open source under the AGPL-3.0 license, with no official paid tier.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$What operating systems does Stash support$q$, $q$Stash runs on Windows, macOS, and Linux, and is commonly deployed via Docker.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$How do I access Stash once it is running$q$, $q$Stash is accessed through a local web interface, available by default at localhost:9999.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Does Stash require ffmpeg$q$, $q$Yes, Stash requires ffmpeg for transcoding and will download a copy automatically if it is not already installed.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$What is StashDB$q$, $q$StashDB is a crowd-sourced repository of scene, studio, and performer metadata that Stash's scrapers can use to enrich a user's library.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$What programming language is Stash written in$q$, $q$Stash is written primarily in Go, with a TypeScript front end.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Where can I get support for Stash$q$, $q$Support is available through the official documentation at docs.stashapp.cc, a Discord server, and GitHub discussions.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Personal media library organization$q$, $q$Individuals with large personal video and image collections use Stash to tag, catalog, and search their files from a local web interface.$q$, $q$Self-hosting enthusiasts and home media curators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Metadata enrichment for existing collections$q$, $q$Users with unorganized media libraries use Stash's scraper and plugin system to automatically pull in titles, performers, and studio metadata.$q$, $q$Users with large unorganized media archives$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Privacy-focused local media management$q$, $q$Users who prefer to avoid cloud storage for personal media rely on Stash's fully self-hosted architecture to keep data on their own hardware.$q$, $q$Privacy-conscious self-hosters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code and application","Tagging and metadata scraping","Plugin and scraper ecosystem","StashDB integration","Community support via Discord and GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$overview$q$, $q$What Is Stash$q$, 2, ARRAY[$q$Stash is a free, open-source, self-hosted web application for organizing personal media collections. It runs on the user's own hardware rather than in the cloud, giving full control over how files are stored, tagged, and browsed.$q$, $q$The project is maintained by the stashapp open-source community and distributed at stashapp.cc. It is written primarily in Go with a TypeScript front end, and is licensed under the GNU Affero General Public License v3.0. It should not be confused with the unrelated Stash investing and personal finance app; stashapp.cc is strictly a self-hosted media organizer.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Stash lets users tag, categorize, and search their media library, and gathers metadata automatically through an extensible plugin and scraper system built by the community. It tracks statistics across performers, tags, and studios, and integrates with StashDB, a crowd-sourced metadata repository that scrapers can pull structured information from.$q$, $q$The application supports a wide range of video and image formats and uses ffmpeg for transcoding (downloading it automatically if not already installed). It runs via Docker or as a native application on Windows, macOS, and Linux, and is accessed through a local web interface.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Stash is entirely free and open source under the AGPL-3.0 license. There is no paid tier from the core project; the community also supports the project through voluntary contributions via Open Collective. Some third-party providers offer paid managed hosting for Stash, but the software itself is free to self-host.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7fcb3565-0b7e-4173-967c-63ee940c83a4', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Flat-file-first content storage$q$, $q$Content can be stored as Markdown and YAML files that live alongside code and are trackable in Git, with an optional database driver.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Blueprints and field types$q$, $q$Content structures are defined with Blueprints using more than 40 built-in field types for flexible content modeling.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Headless REST and GraphQL API$q$, $q$Pro-tier sites can serve content headlessly through REST or GraphQL for decoupled front ends.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Multi-site and multilingual support$q$, $q$A single Statamic installation can power multiple sites and languages from one control panel.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Git-based workflows$q$, $q$Git integration and automation in the control panel support developer workflows that track content changes like code.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Live Preview$q$, $q$Editors can preview content changes in real time before publishing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Roles and permissions$q$, $q$Pro tier supports unlimited user accounts with configurable roles and permissions for editorial teams.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$White-label customization$q$, $q$Agencies can rebrand the control panel for client-facing deployments on the Pro tier.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Free Core tier with no cost for single-admin, single-site use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Flat-file storage enables true Git-based content version control$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Built on Laravel, appealing to PHP and Laravel developers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Polished, modern control panel that non-technical editors can use comfortably$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Flexible headless API options for decoupled front-end architectures$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Pro tier requires a per-site license fee, which can add up for agencies managing many sites$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Smaller plugin and theme ecosystem compared to WordPress$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Requires PHP and Laravel familiarity to extend or customize deeply$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Flat-file storage can become harder to manage at very large content scale$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Is Statamic free to use$q$, $q$Statamic Core is free forever for single-admin use. The Pro tier, needed for most production client sites, costs 349 dollars per site for the first year and 99 dollars per year to renew.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$What framework is Statamic built on$q$, $q$Statamic is built on Laravel, a popular PHP web application framework.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Does Statamic require a database$q$, $q$No. Statamic is flat-file-first, storing content as Markdown and YAML files, though it also supports a database driver for teams that prefer that approach.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Who founded Statamic$q$, $q$Statamic was founded in 2012 by Jack McDade, with Jason Varga later joining as a core developer.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Can Statamic be used as a headless CMS$q$, $q$Yes, the Pro tier includes a headless REST API and GraphQL API for decoupled front-end architectures.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Does Statamic support multiple languages and sites$q$, $q$Yes, Statamic Pro supports multi-site and multilingual publishing from a single installation.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Where is Statamic based$q$, $q$Statamic is headquartered in Ormond Beach, Florida, United States, and operates as a small, self-funded team.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Is there a discount for nonprofits or schools$q$, $q$Yes, verified nonprofits, schools, and universities receive a 20 percent discount on Statamic's first-party products.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Agency client websites$q$, $q$Web agencies use Statamic's white-label Pro tier and Git-based workflows to build and maintain marketing sites for multiple clients.$q$, $q$Web design and development agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Developer-controlled content sites$q$, $q$Laravel developers use Statamic's flat-file storage to keep content under version control alongside application code.$q$, $q$Laravel and PHP developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Headless content delivery$q$, $q$Teams building decoupled front ends use Statamic Pro's REST and GraphQL APIs to serve content to custom applications.$q$, $q$Development teams building headless architectures$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Core$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["One admin user account","One content form","Blueprints with 40-plus field types","Unlimited collections and taxonomies","Asset management","Live Preview"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Pro$q$, $q$$349 per site (first year), $99/year renewal$q$, $q$annual$q$, NULL, $q$["Everything in Core","Unlimited user accounts and roles","Revisions, drafts, and content history","Headless REST and GraphQL API","Multi-site and multilingual support","White-label customization","Git integration and automation"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Everything in Pro","Dedicated premium support with SLA","SSO, two-factor authentication, and audit logging","Custom procurement and compliance support","Onboarding, training, and consulting"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$overview$q$, $q$What Is Statamic$q$, 2, ARRAY[$q$Statamic is a content management system built on top of Laravel, designed around the idea that content can live in flat files rather than being locked inside a database. Founded in 2012 by Jack McDade, Statamic set out to give developers Git-friendly, version-controllable content while still offering a polished editing experience for non-technical users.$q$, $q$The company is headquartered in Ormond Beach, Florida, and remains a small, self-funded team of roughly 2 to 10 people. Core developer Jason Varga joined the project after building an early e-commerce add-on, and the two have driven Statamic's development since.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Statamic's flat-file-first approach lets content, structured through Blueprints and more than 40 field types, be stored as Markdown and YAML files that can be tracked in Git alongside code, while also supporting a database driver for teams that prefer it. The control panel gives editors a clean, modern interface for managing collections, taxonomies, and assets without touching code.$q$, $q$Pro-tier features add unlimited user accounts and roles, content revisions and version history, a headless REST and GraphQL API for decoupled front ends, multi-site and multilingual publishing, and white-label customization for agencies building on behalf of clients. Git integration and automation tools in the control panel support CI/CD-style content workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9925de6-28c3-40f9-a148-3dd0616aa66f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Statamic Core is free forever for single-admin use, and Pro is free during development and staging. For production use, the Pro license costs 349 dollars per site for the first year, renewing at 99 dollars per year thereafter, and unlocks multi-user editing, the headless API, and other production features most client projects need. An Enterprise tier offers custom pricing with SSO, two-factor authentication, audit logging, and dedicated premium support with an SLA. Verified nonprofits, schools, and universities receive a 20 percent discount on first-party products.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Feature flags and config management$q$, $q$Unlimited feature flag and configuration checks let teams control feature rollouts without redeploying code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$A/B testing and experimentation$q$, $q$Built-in statistical engine supports running and analyzing A/B tests and more advanced experiment designs.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Product and web analytics$q$, $q$Usage analytics are integrated directly with flag and experiment data for unified reporting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Session replay$q$, $q$Teams can watch recorded user sessions to see how real users interact with new features.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Change reviews and approvals$q$, $q$Pro and Enterprise tiers add workflow controls so flag and experiment changes can be reviewed before going live.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Warehouse-native deployment$q$, $q$Enterprise customers can run Statsig against their own data warehouse for data residency and integration needs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$SSO and role-based access control$q$, $q$Enterprise tier adds single sign-on and granular access controls for larger organizations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Unlimited seats on the free tier$q$, $q$The Developer plan includes unlimited seats, letting whole teams collaborate without per-seat costs.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Generous free Developer tier with unlimited flag checks and unlimited seats$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Combines feature flags, experimentation, and analytics in one platform instead of separate tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Backed by rapid growth and, since 2025, OpenAI's resources following its acquisition$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Advanced experimentation and analytics on paid tiers support rigorous statistical testing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Session replay is included even on the free tier$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Event-based pricing on Pro can grow with product usage, adding cost as event volume increases$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Enterprise-grade capabilities like warehouse-native deployment and SSO require a custom contract$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Recent OpenAI acquisition (2025) may bring product direction changes for existing customers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Advanced analytics retention and change review workflows are gated behind paid tiers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Is Statsig free to use$q$, $q$Yes, Statsig has a free Developer tier with 2 million monthly events, unlimited feature flag checks, and 50,000 monthly session replays.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Who founded Statsig and when$q$, $q$Statsig was founded in 2021 by Vijaye Raji, a former Facebook engineering leader.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Where is Statsig headquartered$q$, $q$Statsig is headquartered in Bellevue, Washington, United States.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Did OpenAI acquire Statsig$q$, $q$Yes, OpenAI acquired Statsig in September 2025 in an all-stock deal valued at 1.1 billion dollars.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$How much does Statsig Pro cost$q$, $q$The Pro tier costs 150 dollars per month, including 5 million events, with additional events billed at 0.05 dollars per 1,000.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$What does Statsig's platform include$q$, $q$Statsig combines feature flags and configuration management, A/B testing and experimentation, session replay, and product analytics in one platform.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Does Statsig offer an Enterprise plan$q$, $q$Yes, Statsig's Enterprise tier offers custom pricing with warehouse-native deployment, SSO, role-based access control, and HIPAA eligibility.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$How much funding did Statsig raise before being acquired$q$, $q$Statsig raised about 153.4 million dollars across a Series A, Series B, and Series C, reaching a 1.1 billion dollar valuation before OpenAI's acquisition.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Safe feature rollouts$q$, $q$Engineering teams use Statsig's feature flags to gradually roll out new features and instantly roll them back if issues arise.$q$, $q$Engineering and platform teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Product experimentation and A/B testing$q$, $q$Product teams run A/B tests and more advanced experiments through Statsig to measure the impact of changes before a full rollout.$q$, $q$Product managers and growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Unified product analytics and experiment impact analysis$q$, $q$Teams use Statsig's integrated analytics to see how feature flags and experiments affect real product usage metrics in one place.$q$, $q$Data and analytics teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Developer$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["2 million events per month","Unlimited feature flag and config checks","50,000 session replays per month","A/B tests and experimentation","1-year analytics retention","Unlimited seats"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Pro$q$, $q$$150/month$q$, $q$monthly$q$, NULL, $q$["5 million events included ($0.05 per 1,000 additional)","Advanced experimentation","Advanced product analytics","Unlimited analytics retention","Change reviews and approvals","100,000 session replays per month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Warehouse-native deployment","Outgoing data integrations","Data warehouse imports","SSO and role-based access control","Priority support","HIPAA eligibility (BAA required)"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$overview$q$, $q$What Is Statsig$q$, 2, ARRAY[$q$Statsig is a product development platform that combines feature flagging, A/B testing and experimentation, session replay, and product analytics into a single system, aimed at engineering and product teams that want to ship and measure changes without assembling multiple point tools.$q$, $q$The company was founded in 2021 by Vijaye Raji, previously an engineering leader at Facebook, and is headquartered in Bellevue, Washington. Statsig grew quickly, raising a Series A and Series B led by Sequoia Capital before a 100 million dollar Series C led by ICONIQ Growth in May 2025 at a 1.1 billion dollar valuation. In September 2025, OpenAI acquired Statsig in an all-stock deal also valued at 1.1 billion dollars.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Statsig provides unlimited feature flag and config checks, letting engineering teams roll features out gradually and roll them back instantly if something goes wrong. Its experimentation engine runs A/B tests and more advanced experiment designs with statistical rigor built in.$q$, $q$Product and web analytics are integrated directly with experimentation data, so teams can see the downstream impact of a feature flag or experiment on real usage metrics. Session replay capabilities let teams watch how users actually interact with new features, and higher tiers add change reviews and approvals, API controls, warehouse-native deployment, and SSO for larger organizations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Statsig's Developer tier is free, with no credit card required, and includes 2 million monthly events, unlimited feature flag checks, 50,000 monthly session replays, and unlimited seats. The Pro tier costs 150 dollars per month, includes 5 million events with additional events billed at 0.05 dollars per 1,000, and adds advanced experimentation, advanced analytics, unlimited analytics retention, and change reviews. The Enterprise tier uses custom, volume-based contracts and adds warehouse-native deployment, data integrations, SSO, role-based access control, and HIPAA eligibility.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Scheduled and bulk publishing$q$, $q$Content can be scheduled individually or in bulk across multiple social profiles, with best-time-to-post recommendations.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Unified social inbox$q$, $q$Comments, messages, and mentions from all connected profiles are consolidated into a single inbox with a rule engine for automation.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Social media reporting$q$, $q$Built-in reporting covers performance metrics with up to 18 months of historical data on higher tiers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Google Business Profile integration$q$, $q$Businesses can manage their Google Business Profile listings alongside their other social channels.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$AI sentiment analysis$q$, $q$Premium and higher tiers use AI to gauge the sentiment of incoming comments and messages.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Approval workflows$q$, $q$Content assignment and approval workflows let teams route posts for review before publishing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Competitor benchmarking and listening$q$, $q$Premium and Enterprise tiers include competitor benchmarking and social or web listening tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$CRM and enterprise integrations$q$, $q$Enterprise plans connect to HubSpot and Salesforce, and support SAML SSO and API access.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Positioned as a lower-cost alternative to Sprout Social and Hootsuite with similar feature depth$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Unified social inbox simplifies managing comments and messages across many profiles$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Dedicated Agency plan with per-client pricing suits agencies managing multiple accounts$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$14-day free trial with no credit card required$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$AI sentiment analysis and listening tools available on Premium and above$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Entry-level Lite plan supports only 1 user and 5 profiles, limiting it for larger teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Advanced features like sentiment analysis and competitor benchmarking require the Premium tier or higher$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Enterprise-grade integrations (CRM, SSO) require custom pricing and sales contact$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Pricing is higher than some lightweight scheduling-only tools aimed at solo creators$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$How much does Statusbrew cost$q$, $q$Statusbrew's Lite plan starts at 89 dollars per month for 1 user and 5 social profiles, with Standard at 179 dollars per month and Premium at 299 dollars per month for larger teams.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Does Statusbrew offer a free trial$q$, $q$Yes, Statusbrew offers a 14-day free trial with no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$When was Statusbrew founded$q$, $q$Statusbrew was founded in 2011.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Does Statusbrew have a plan for agencies$q$, $q$Yes, Statusbrew offers an Agency plan starting at 49 dollars per month per client, with unlimited spaces, calendars, and reports.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$What social inbox features does Statusbrew provide$q$, $q$Statusbrew consolidates comments, messages, and mentions from all connected social profiles into one inbox, with a rule engine to automate routing and responses.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Does Statusbrew integrate with Google Business Profile$q$, $q$Yes, Statusbrew's Standard tier and above include Google Business Profile integration.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Does Statusbrew support enterprise SSO$q$, $q$Yes, the Enterprise plan includes SAML SSO along with CRM integrations and dedicated account management.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Who is Statusbrew designed for$q$, $q$Statusbrew serves small and midsize businesses, agencies, and enterprises that need to manage multiple social media profiles from one platform.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Multi-profile social media publishing$q$, $q$Marketing teams use Statusbrew to schedule and bulk-publish content across many social profiles from one calendar.$q$, $q$Marketing and social media teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Unified customer engagement across social channels$q$, $q$Support and community teams use Statusbrew's shared inbox to respond to comments and messages from all social profiles in one place.$q$, $q$Social media and customer support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Agency management of multiple client accounts$q$, $q$Agencies use Statusbrew's per-client Agency plan to manage social media publishing and reporting for many clients under one platform.$q$, $q$Marketing and social media agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Lite$q$, $q$$89/month$q$, $q$annual (monthly available)$q$, NULL, $q$["1 user","5 social profiles","Scheduled and bulk publishing","Best-time-to-post recommendations","All-in-one inbox","Email support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Standard$q$, $q$$179/month$q$, $q$annual (monthly available)$q$, NULL, $q$["3 users","10 social profiles","BrewLink-in-bio","Social media reporting (18 months of data)","Google Business Profile integration","Rule engine for comments","Email and chat support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Premium$q$, $q$$299/month$q$, $q$annual (monthly available)$q$, NULL, $q$["6 users (expandable)","15 social profiles (expandable)","AI sentiment analysis","Assignment and approval workflows","Team and SLA reporting","Competitor benchmarking","Social and web listening","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Unlimited users and profiles","Dedicated account manager","HubSpot and Salesforce integration","API access","SAML SSO","Compliance support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$Agency$q$, $q$From $49/month per client$q$, $q$monthly$q$, NULL, $q$["Unlimited spaces","Unlimited calendars","Unlimited reports"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$overview$q$, $q$What Is Statusbrew$q$, 2, ARRAY[$q$Statusbrew is a social media management platform that helps businesses, agencies, and enterprises publish content, manage social inboxes, and report on performance across multiple social profiles from a single dashboard. Founded in 2011, the company has grown into a team of roughly 11 to 50 people working across several continents.$q$, $q$Statusbrew positions itself as a lower-cost alternative to larger platforms like Sprout Social and Hootsuite, aiming for close feature parity while undercutting them on price. It serves customers ranging from small businesses managing a handful of social profiles to agencies running social media for many clients at once.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform supports scheduled and bulk publishing across social channels, with a best-time-to-post recommendation engine to help maximize reach. An all-in-one social inbox consolidates comments, messages, and mentions from every connected profile into a single stream, with a rule engine to automate responses and routing.$q$, $q$Higher tiers add BrewLink-in-bio pages, social media reporting with up to 18 months of historical data, Google Business Profile integration, AI-driven sentiment analysis, assignment and approval workflows for content review, competitor benchmarking, and social and web listening. Enterprise customers get CRM integrations with HubSpot and Salesforce, SAML SSO, API access, and a dedicated account manager.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79992a38-a613-4b56-91d4-2a13d7ad2204', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Statusbrew's Lite plan starts at 89 dollars per month for 1 user and 5 social profiles. Standard is 179 dollars per month for 3 users and 10 profiles, and Premium is 299 dollars per month for up to 6 users and 15 profiles, adding AI sentiment analysis and approval workflows. Enterprise pricing is custom and includes unlimited users and profiles. Agencies can also choose a per-client Agency plan starting at 49 dollars per month per client. All plans include a 14-day free trial with no credit card required.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Uptime monitoring$q$, $q$Checks website availability at intervals as fast as 30 seconds from a global network of testing locations.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Page speed monitoring$q$, $q$Tracks page load time trends over time to catch performance regressions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$SSL certificate monitoring$q$, $q$Alerts teams before SSL certificates expire to avoid browser security warnings.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Domain expiration monitoring$q$, $q$Tracks domain registration expiration dates and warns before a domain lapses.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Server monitoring$q$, $q$Available on paid tiers, tracks CPU, memory, and disk usage on underlying servers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Global testing locations$q$, $q$Checks run from more than 30 locations worldwide to reflect real user experience by region.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Public status pages$q$, $q$Incident communication tools let teams publish status pages to keep users informed during outages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Multi-channel alerting$q$, $q$Alerts can be delivered via email, SMS, and third-party integrations when issues are detected.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Free tier covers basic uptime, page speed, domain, and SSL monitoring at no cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Global network of 30-plus testing locations for realistic monitoring by region$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Test intervals as fast as 30 seconds on the Business plan$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Broad monitoring coverage in one platform (uptime, speed, SSL, domain, server)$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Established provider founded in 2012 with a long operating history$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Free tier's 5-minute test interval is slower than paid tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Server monitoring is only available starting on paid plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Small team size (2-10 employees) relative to some enterprise monitoring competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Enterprise-level features like constant check rates and dedicated locations require custom pricing$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Does StatusCake have a free plan$q$, $q$Yes, StatusCake offers a free plan with 10 uptime monitors, 5-minute test intervals, and one each of page speed, domain, and SSL monitors.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$How much does StatusCake cost$q$, $q$Paid plans start with the Superior plan from about 20.41 dollars per month billed annually, and the Business plan from about 66.66 dollars per month billed annually. Enterprise pricing is custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$How often does StatusCake check my website$q$, $q$Check intervals range from 5 minutes on the free plan down to 30 seconds on the Business plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$When was StatusCake founded$q$, $q$StatusCake was founded in 2012 by James Barnes and is headquartered in London, United Kingdom.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Does StatusCake monitor SSL certificates and domains$q$, $q$Yes, StatusCake includes SSL certificate monitoring and domain expiration monitoring on all plans, with higher limits on paid tiers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Does StatusCake support server monitoring$q$, $q$Yes, server monitoring for CPU, memory, and disk usage is available starting on the Superior paid plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$How many locations does StatusCake test from$q$, $q$StatusCake tests from more than 30 global locations to reflect performance and availability by region.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Does StatusCake offer public status pages$q$, $q$Yes, StatusCake includes incident communication tools, including public status pages, to keep users informed during outages.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Website uptime alerting$q$, $q$Businesses use StatusCake to get alerted the moment their website or application goes down, before customers notice.$q$, $q$Website owners and small businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$DevOps performance and infrastructure monitoring$q$, $q$DevOps teams use StatusCake's page speed and server monitoring to catch performance regressions and resource issues early.$q$, $q$DevOps and infrastructure teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$SSL and domain expiration tracking$q$, $q$IT teams use StatusCake to avoid unexpected outages caused by expired SSL certificates or lapsed domain registrations.$q$, $q$IT administrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Free$q$, $q$$0/month$q$, $q$N/A$q$, NULL, $q$["10 uptime monitors","5-minute test intervals","1 page speed monitor","1 domain monitor","1 SSL monitor"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Superior$q$, $q$From $20.41/month$q$, $q$annual (monthly available)$q$, NULL, $q$["100 uptime monitors","1-minute test intervals","15 page speed monitors","50 domain monitors","50 SSL monitors","3 server monitors"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Business$q$, $q$From $66.66/month$q$, $q$annual (monthly available)$q$, NULL, $q$["300 uptime monitors","30-second test intervals","30 page speed monitors","120 domain monitors","100 SSL monitors","10 server monitors"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Unlimited monitors","Constant check rate","Dedicated uptime and page speed locations","Service-creditable SLAs","Regular account reviews"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$overview$q$, $q$What Is StatusCake$q$, 2, ARRAY[$q$StatusCake is a website monitoring platform that tracks uptime, page speed, SSL certificate validity, domain expiration, and server performance to alert teams before issues affect visitors. Founded in 2012 by James Barnes, the company is headquartered in London, United Kingdom, and remains a small, privately held team.$q$, $q$The platform checks websites from more than 30 global locations, letting teams verify availability and performance from the regions where their users actually are, rather than relying on a single test location.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Uptime monitoring runs at intervals as fast as 30 seconds on higher tiers, with alerts sent through email, SMS, and integrations when a site goes down. Page speed monitoring tracks how load times change over time, while SSL and domain monitors flag certificates and domains approaching expiration before they lapse.$q$, $q$Server monitoring, available on paid tiers, tracks resource usage like CPU, memory, and disk on the underlying infrastructure. StatusCake also provides incident communication tools, including public status pages, so teams can keep users informed during outages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c4af54de-4e6f-4013-b444-8a17c0797dd0', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$StatusCake offers a free plan with 10 uptime monitors, 5-minute test intervals, and one each of page speed, domain, and SSL monitors. The Superior plan starts from about 20.41 dollars per month billed annually and raises limits to 100 uptime monitors, 1-minute intervals, and more page speed, domain, and SSL monitors, plus 3 server monitors. The Business plan, StatusCake's most popular tier, starts from about 66.66 dollars per month billed annually, offering 300 uptime monitors at 30-second intervals and higher limits across all monitor types. An Enterprise plan offers custom pricing with unlimited monitors and dedicated monitoring locations.$q$]::text[], 2);
