-- Enrichment marathon batch: Stalwart Mail Server, Standard Notes, Starlight, Stash, Statamic, Statsig, Statusbrew, StatusCake

-- ── Stalwart Mail Server ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Stalwart is an open-source, all-in-one mail and collaboration server written in Rust that combines JMAP, IMAP4, POP3, SMTP, CalDAV, CardDAV, and WebDAV in a single self-hosted platform.$q$, short_description),
  pricing_model = COALESCE($q$open-source with paid enterprise edition$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community edition); Enterprise from about 2 euros per mailbox per year$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Stalwart Mail Server: Open-Source All-in-One Email Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Stalwart is a free, open-source mail and collaboration server combining JMAP, IMAP, POP3, SMTP, CalDAV, CardDAV, and WebDAV. Self-hosted and Rust-powered.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Stalwart Mail Server is an open-source, self-hosted mail and collaboration server built in Rust by Stalwart Labs, founded in 2022 and based in London, United Kingdom. It unifies JMAP, IMAP4rev2, IMAP4rev1, POP3, SMTP, ManageSieve, CalDAV, CardDAV, and WebDAV in a single binary, positioning itself as an all-in-one alternative to running separate mail, calendar, and contacts servers. Core features include built-in DKIM, DMARC, SPF, and ARC support for message authentication, automated DKIM key rotation, ACME-based TLS certificate renewal, integrated DNS management for providers like Cloudflare and Route 53, a web-based admin dashboard, multi-tenant architecture with per-user and per-tenant quotas, and Sieve scripting support for every IANA-registered extension. The Community edition is free and fully open source (available on GitHub), while a paid Enterprise edition adds premium support, advanced management tooling, and licensing priced per mailbox (roughly 2 euros per mailbox per year for smaller deployments, decreasing at higher volumes). Stalwart is aimed at system administrators, privacy-focused organizations, and developers who want to self-host a modern, standards-compliant email stack instead of relying on legacy software like Postfix, Dovecot, or hosted providers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'db5dc978-1f33-4ece-86f5-07c85e0d3438';

