-- ── Standard Notes ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Standard Notes is an end-to-end encrypted note-taking app that syncs across all major platforms, built for privacy-conscious individuals and teams.$q$, short_description),
  pricing_model = COALESCE($q$freemium subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free (Productivity plan from about 90 dollars per year)$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Chicago, Illinois, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Standard Notes: End-to-End Encrypted Note-Taking App$q$, seo_title),
  seo_meta_description = COALESCE($q$Standard Notes is an end-to-end encrypted, cross-platform note-taking app with a free tier and paid plans for extended history, files, and themes.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Standard Notes is an end-to-end encrypted note-taking application founded by Mo Bitar in 2016 in Chicago, Illinois, created as a privacy-focused response to policy changes at competitors like Evernote. In April 2024 it was acquired by Proton AG, joining the Proton suite of privacy products alongside Proton Mail and Proton VPN. The app provides zero-knowledge, audited end-to-end encryption so that only the user can decrypt their notes, with sync across web, desktop, and mobile platforms. Standard Notes operates on a freemium model: the free tier includes markdown support, nested folders, and core organization features, while paid plans (roughly 90 dollars per year for the Productivity tier and around 120 dollars per year for the Professional tier) unlock features like extended note history, file storage (up to 100GB on the top tier), custom themes and editors, and subscription sharing. It is used by individuals, journalists, and small teams who prioritize data privacy and want an alternative to cloud note apps that do not encrypt content client-side.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '19834a87-bdcd-4d0a-b9a5-f013e990b7b2';

