-- ── Starlight ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Starlight is a free, open-source documentation site framework built on Astro, offering navigation, search, internationalization, and accessibility out of the box.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Starlight: Open-Source Documentation Site Builder for Astro$q$, seo_title),
  seo_meta_description = COALESCE($q$Starlight is a free, open-source Astro-based framework for building fast, accessible, searchable documentation websites with built-in i18n.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Starlight is a free, open-source documentation site framework built on top of Astro, maintained by the Astro core team (withastro) since its introduction in 2023. It is designed to help developers and technical writers build fast, accessible documentation websites with minimal setup. Starlight ships with automatic sidebar navigation generated from a site's file structure, built-in full-text search powered by Pagefind, built-in internationalization for multilingual documentation, dark and light theme support, and support for Markdown, MDX, and Markdoc content formats. Because it is built on Astro, Starlight ships minimal JavaScript to the browser by default, producing fast page loads, and it supports framework-agnostic UI components so teams can drop in React, Vue, Svelte, or Solid components where needed. Starlight is entirely free and open source, distributed under an open-source license on GitHub, with no paid tier or company behind it beyond the Astro project itself. It suits open-source projects, developer tools, API references, and any team that wants a polished documentation site without building one from scratch.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ffe3fec8-5847-4750-b01a-593c7901730d';

