-- ── Stash ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Stash (stashapp.cc) is a free, open-source, self-hosted media organizer written in Go for cataloging, tagging, and browsing personal video and image collections.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Stash: Open-Source Self-Hosted Media Organizer (stashapp.cc)$q$, seo_title),
  seo_meta_description = COALESCE($q$Stash is a free, open-source, self-hosted media organizer written in Go with tagging, metadata scraping, statistics, and plugin support.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Stash, distributed from stashapp.cc and developed in the stashapp GitHub organization, is a free, open-source, self-hosted web application for organizing and browsing personal media libraries. It is not related to the Stash investing or personal finance app; this Stash is a media cataloging tool written primarily in Go with a TypeScript front end, licensed under the GNU Affero General Public License v3.0 (AGPL-3.0). Users run Stash on their own hardware, typically via Docker, on Windows, macOS, or Linux, and access it through a local web interface (by default at localhost:9999). Core capabilities include tagging and organizing video and image files, pulling metadata from the internet through an extensible community-built scraper and plugin system, tracking statistics on performers, tags, and studios, and supporting a wide range of video and image formats (with ffmpeg used for transcoding). The project also maintains StashDB, a crowd-sourced metadata repository that scrapers can pull from. Stash has an active open-source community with documentation at docs.stashapp.cc, a Discord server, GitHub discussions, and roughly 12,700 GitHub stars. It is aimed at users who want full local control over organizing large personal media collections rather than relying on cloud services.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7fcb3565-0b7e-4173-967c-63ee940c83a4';

