-- ── Statamic ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Statamic is a flat-file-first, hybrid CMS built on Laravel that lets developers manage content with Git-friendly files or a database, paired with a polished control panel for editors.$q$, short_description),
  pricing_model = COALESCE($q$freemium (free Core tier, paid Pro licenses)$q$, pricing_model),
  starting_price = COALESCE($q$Free (Core); Pro from $349 per site first year, $99/year renewal$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$2-10 employees$q$, company_size),
  headquarters = COALESCE($q$Ormond Beach, Florida, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Statamic: Flat-File Laravel CMS for Developers and Editors$q$, seo_title),
  seo_meta_description = COALESCE($q$Statamic is a Laravel-powered, flat-file-first CMS with a free Core tier and Pro licensing from $349 per site, built for developers and content editors.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Statamic is a content management system built on the Laravel PHP framework, founded in 2012 by Jack McDade (with early co-founder Mubashar Iqbal) and headquartered in Ormond Beach, Florida. It is a small, self-funded, privately held company with roughly 2 to 10 employees, with Jason Varga later joining as a core developer. Statamic is known for being flat-file-first, meaning content can be stored as version-controllable files (Markdown, YAML) rather than requiring a database, while also supporting a database-driven mode for teams that prefer it. It targets developers who want Git-based workflows and full code control, paired with a polished control panel that non-technical editors can use to manage content. Pricing follows a freemium model: the Core tier is free forever for single-admin sites, while the Pro tier costs 349 dollars per site for the first year (99 dollars per year to renew) and unlocks unlimited users and roles, revisions and content history, headless REST and GraphQL APIs, multi-site and multilingual support, and white-label customization. An Enterprise tier offers custom pricing with SSO, audit logging, and dedicated support. Statamic is popular for marketing sites, blogs, documentation sites, and client projects built by Laravel developers and agencies.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f9925de6-28c3-40f9-a148-3dd0616aa66f';

