-- ── Statsig ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Statsig is a product development platform combining feature flags, A/B testing and experimentation, and product analytics in a single system built for engineering-led growth.$q$, short_description),
  pricing_model = COALESCE($q$freemium subscription (usage-based)$q$, pricing_model),
  starting_price = COALESCE($q$Free (Developer tier); Pro from $150/month$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Bellevue, Washington, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Statsig: Feature Flags, Experimentation and Product Analytics$q$, seo_title),
  seo_meta_description = COALESCE($q$Statsig unifies feature flags, A/B testing, and product analytics. Free Developer tier, Pro from $150/month, acquired by OpenAI in 2025.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Statsig is a product development platform that unifies feature flags, A/B testing and experimentation, session replay, and product analytics in a single system. It was founded in 2021 by Vijaye Raji, a former Facebook engineering leader, and is headquartered in Bellevue, Washington, with roughly 51 to 200 employees. Statsig raised a Series A led by Sequoia Capital in 2021, a Series B led by Sequoia in 2022, and a 100 million dollar Series C led by ICONIQ Growth in May 2025 at a 1.1 billion dollar valuation, for total funding of about 153.4 million dollars. In September 2025, Statsig was acquired by OpenAI in an all-stock deal valued at 1.1 billion dollars, with plans to continue operating its platform for external customers. Statsig's pricing includes a free Developer tier with 2 million monthly events, unlimited feature flag checks, and 50,000 monthly session replays; a Pro tier at 150 dollars per month with 5 million included events, advanced experimentation, and unlimited analytics retention; and a custom-priced Enterprise tier with warehouse-native deployment, SSO, and HIPAA eligibility. Statsig is used by engineering and product teams at companies of all sizes to ship features safely, run experiments, and analyze product usage without stitching together separate tools.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cd05bd69-56cc-4c9d-ab2c-9a1a41c43fe6';

