-- ── Statusbrew ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Statusbrew is a social media management platform that lets businesses and agencies publish, monitor, and analyze content across multiple social profiles from one shared inbox.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$From $89/month (Lite plan, annual billing)$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Amritsar, Punjab, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Statusbrew: Social Media Management for Teams and Agencies$q$, seo_title),
  seo_meta_description = COALESCE($q$Statusbrew is a social media management platform for scheduling, inbox management, and reporting across profiles. Plans start at $89/month.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Statusbrew is a social media management platform founded in 2011, built to help small and midsize businesses, agencies, and enterprises manage social profiles, publish content, and unify social inboxes from one dashboard. The company has around 11 to 50 employees working across multiple continents, with operational roots in Amritsar, Punjab, India, and a US corporate registration in Wilmington, Delaware. Statusbrew positions itself as offering close feature parity with larger competitors like Sprout Social and Hootsuite at a lower price. Its plans include Lite at 89 dollars per month for 1 user and 5 social profiles, Standard at 179 dollars per month for 3 users and 10 profiles, Premium at 299 dollars per month for 6 users and 15 profiles (with AI sentiment analysis and approval workflows), and a custom-priced Enterprise tier with dedicated account management, CRM integrations, and SSO. An Agency plan starts at 49 dollars per month per client. All paid plans are billed monthly or annually and come with a 14-day free trial requiring no credit card. Core capabilities include scheduled and bulk publishing, a shared social inbox for managing comments and messages, social media reporting, Google Business Profile integration, and, on higher tiers, competitor benchmarking and social listening.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '79992a38-a613-4b56-91d4-2a13d7ad2204';

