-- ── StatusCake ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$StatusCake is a website monitoring platform offering uptime, page speed, SSL, domain, and server monitoring from a global network of testing locations.$q$, short_description),
  pricing_model = COALESCE($q$freemium subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free; Superior plan from about $20.41/month (annual)$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$2-10 employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$StatusCake: Website Uptime and Performance Monitoring$q$, seo_title),
  seo_meta_description = COALESCE($q$StatusCake monitors website uptime, page speed, SSL, and domains from 30-plus global locations. Free tier available; paid plans from about $20/month.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$StatusCake is a website monitoring platform founded in 2012 by James Barnes and headquartered in London, United Kingdom, operating as a small, privately held company. It monitors uptime, page speed, SSL certificates, domain expiration, and server performance from a network of more than 30 global testing locations, with check intervals as fast as 30 seconds on higher tiers. StatusCake offers a free plan covering 10 uptime monitors with 5-minute test intervals, one page speed monitor, one domain monitor, and one SSL monitor. The Superior plan, priced from about 20.41 dollars per month billed annually (19.99 euros monthly), raises limits to 100 uptime monitors with 1-minute intervals, 15 page speed monitors, 50 domain monitors, 50 SSL monitors, and 3 server monitors. The Business plan, from about 66.66 dollars per month billed annually, is the most popular tier and supports 300 uptime monitors at 30-second intervals, 30 page speed monitors, 120 domain monitors, 100 SSL monitors, and 10 server monitors, along with support for larger teams. A custom-priced Enterprise plan adds unlimited monitors, constant check rates, dedicated monitoring locations, and service-credit-backed SLAs. StatusCake is used by developers, DevOps teams, and small-to-midsize businesses that need to detect downtime and performance issues before customers do.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
